const config = $input.first().json;
const base = config.GitRawBaseURL;
const branch = config.GitBranch || 'test';
const path = config.MappingsPath || 'BreaksRecovery/Mapping';

if (!base) {
  throw new Error(
    'System Error: GitRawBaseURL не задан. TDR v3 §6.5: маппинги загружаются из git. Укажите URL raw-файлов в GetConfig.',
  );
}

const baseUrl = String(base).replace(/\/$/, '');
const isStash =
  /stash\.|\/projects\/[^/]+\/repos\//i.test(baseUrl) &&
  !baseUrl.includes('raw.githubusercontent.com');

const files = [
  'activity',
  'container',
  'news_reading',
  'news_exception_skills',
  'fte_groups',
  'email_fallback',
  'fte_thresholds',
  'runtime',
];

function buildMappingUrl(file) {
  if (isStash) {
    const at = branch.startsWith('refs/') ? branch : `refs/heads/${branch}`;
    return `${baseUrl}/${path}/${file}.json?at=${encodeURIComponent(at)}`;
  }
  return `${baseUrl}/${branch}/${path}/${file}.json`;
}

return files.map((file) => ({
  json: {
    mapping_file: file,
    url: buildMappingUrl(file),
  },
}));

const config = $('Start').first().json;
if (!config?.GitRawBaseURL) {
  throw new Error(
    'System Error: LoadMappings — нет GetConfig на входе Start. Запускайте из Main.',
  );
}

const fetchItems = $input.all();
if (fetchItems.length === 0) {
  throw new Error('System Error: LoadMappings — Fetch JSON не вернул данных.');
}

const buildItems = $('Build Mapping URLs').all();
if (buildItems.length !== fetchItems.length) {
  throw new Error(
    `System Error: LoadMappings — несовпадение items: Build=${buildItems.length}, Fetch=${fetchItems.length}.`,
  );
}

function parseBody(raw) {
  if (raw?.mapping_body !== undefined) return raw.mapping_body;
  const text =
    typeof raw === 'string'
      ? raw
      : typeof raw?.data === 'string'
        ? raw.data
        : typeof raw?.body === 'string'
          ? raw.body
          : null;
  if (text) return JSON.parse(text);
  if (Array.isArray(raw) || (raw && typeof raw === 'object' && !raw.url && !raw.mapping_file)) {
    return raw;
  }
  return undefined;
}

function resolveMappingFile(item, index) {
  if (item.json.mapping_file) return item.json.mapping_file;
  const paired = item.pairedItem;
  const pairedIndex =
    typeof paired?.item === 'number'
      ? paired.item
      : Array.isArray(paired) && typeof paired[0]?.item === 'number'
        ? paired[0].item
        : index;
  return buildItems[pairedIndex]?.json?.mapping_file || buildItems[index]?.json?.mapping_file;
}

const mappings = {};
for (let i = 0; i < fetchItems.length; i++) {
  const item = fetchItems[i];
  const file = resolveMappingFile(item, i);
  const body = parseBody(item.json);
  if (!file || body === undefined || body === null) {
    throw new Error(`System Error: LoadMappings — пустой ответ для ${file || `#${i}`}.json`);
  }
  mappings[file] = body;
}

return [
  {
    json: {
      ...config,
      mappings,
      mappings_loaded_at: new Date().toISOString(),
    },
  },
];
